// ==========================================
// GUIDELINES (base64 encoded) — EXTRACTED VERBATIM
// ==========================================
const GUIDELINES_B64 = {
  "diagram": "",
  "chart": "",
  "mockup": "",
  "interactive": "",
  "art": "",
  "preamble": "",
  "viz_merged": ""
};



// ==========================================
// GUIDELINE DECODING (adapted for Node.js)
// ==========================================
function decodeGuidelines(key) {
  const b64 = GUIDELINES_B64[key];
  if (!b64) return '';
  return Buffer.from(b64, 'base64').toString('utf-8');
}

function getModuleGuidelines(modules) {
  const seen = new Set();
  const parts = [];
  if (FEATURES.viz_merged) {
    parts.push(decodeGuidelines('viz_merged'));
    seen.add('viz_merged');
  }
  for (const m of modules) {
    if (!seen.has(m) && GUIDELINES_B64[m]) {
      seen.add(m);
      parts.push(decodeGuidelines(m));
    }
  }
  if (parts.length === 0) {
    return decodeGuidelines('preamble');
  }
  return parts.join('\n\n---\n\n');
}


