const DEFAULT_MODEL = 'minimax-m2p7';
const MINIMAX_MODEL = 'minimax-m2p7';
const MODEL_PREFIX = 'accounts/fireworks/models/';
const API_URL = 'https://api.fireworks.ai/inference/v1/chat/completions';

function isMinimaxModel(model = getSelectedModel()) {
  return model === MINIMAX_MODEL;
}

function isQwenModel(model = getSelectedModel()) {
  return model.startsWith('qwen');
}

function isGlmModel(model = getSelectedModel()) {
  return model.startsWith('glm');
}

function getSelectedModel() {
  const value = $('modelSelect')?.value?.trim();
  return value || DEFAULT_MODEL;
}

function syncModelBadge() {
  const model = getSelectedModel();
  const badge = $('modelName');
  if (badge) badge.textContent = model;
  return model;
}

// ==========================================
// WIDGET CODE EXTRACTION
// ==========================================
function extractWidgetCode(argStr) {
  const keyIdx = argStr.indexOf('"widget_code"');
  if (keyIdx === -1) return null;
  
  // Find colon
  let pos = keyIdx + '"widget_code"'.length;
  while (pos < argStr.length && (argStr[pos] === ' ' || argStr[pos] === ':')) pos++;
  
  // Find opening quote
  if (pos >= argStr.length || argStr[pos] !== '"') return null;
  pos++; // skip opening quote
  
  let result = '';
  while (pos < argStr.length) {
    const ch = argStr[pos];
    if (ch === '\\' && pos + 1 < argStr.length) {
      const next = argStr[pos + 1];
      if (next === 'n') { result += '\n'; pos += 2; }
      else if (next === 't') { result += '\t'; pos += 2; }
      else if (next === 'r') { result += '\r'; pos += 2; }
      else if (next === '"') { result += '"'; pos += 2; }
      else if (next === '\\') { result += '\\'; pos += 2; }
      else if (next === '/') { result += '/'; pos += 2; }
      else if (next === 'u' && pos + 5 < argStr.length) {
        const hex = argStr.substr(pos + 2, 4);
        if (/^[0-9a-fA-F]{4}$/.test(hex)) {
          result += String.fromCharCode(parseInt(hex, 16));
          pos += 6;
        } else { result += ch; pos++; }
      } else { result += ch; pos++; }
    } else if (ch === '"') {
      break; // end of string
    } else {
      result += ch;
      pos++;
    }
  }
  
  return result || null;
}

function extractWidgetTitle(argStr) {
  const m = argStr.match(/"title"\s*:\s*"([^"\\]*)"/);
  return m ? m[1] : null;
}


// ==========================================
// API CALL (Fireworks streaming)
// ==========================================
async function callAPI(msgs, onChunk, onToolCall, onDone, forceTool) {
  const apiKey = $('apiKey').value.trim();
  if (!apiKey) {
    showError('Please enter your Fireworks API key');
    return;
  }

  const selectedModel = syncModelBadge();
  log('info', `→ ${MODEL_PREFIX + selectedModel} | max_tokens:131072 | reasoning:high | temp:1 | tool_choice:${forceTool ? 'force:'+forceTool : 'auto'} | msgs:${msgs.length}`);
  const body = {
    model: MODEL_PREFIX + selectedModel,
    messages: msgs,
    tools: TOOLS,
    tool_choice: (FEATURES.forceNext && forceTool) ? { type: 'function', function: { name: forceTool } } : 'auto',
    stream: true,
    max_tokens: FEATURES.maxTokensHigh ? 131072 : 65536,
    temperature: FEATURES.tempOne ? 1 : 0.7,
    reasoning_effort: FEATURES.reasoningHigh ? 'high' : 'medium'
  };

  let resp;
  try {
    resp = await fetch(API_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${apiKey}`,
        'Accept': 'text/event-stream'
      },
      body: JSON.stringify(body)
    });
  } catch(e) {
    log('err', `fetch failed: ${e.message}`);
    showError('Network error: ' + e.message);
    onDone(null, e.message);
    return;
  }

  if (!resp.ok) {
    let errText = '';
    try { errText = await resp.text(); } catch(e2) {}
    let errMsg = `API error ${resp.status}`;
    try { 
      const errJson = JSON.parse(errText);
      errMsg += ': ' + (errJson.error?.message || errJson.message || errText.slice(0, 100));
    } catch { errMsg += ': ' + errText.slice(0, 100); }
    log('err', `HTTP ${resp.status}: ${errMsg}`);
    onDone(null, errMsg);
    return;
  }

  const reader = resp.body.getReader();
  const decoder = new TextDecoder();
  let buffer = '';
  
  // Tool call accumulation
  const toolCallBuffers = {};
  let currentToolIndex = -1;
  let assistantText = '';
  let assistantReasoning = '';
  let finishReason = null;
  
  try {
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      
      buffer += decoder.decode(value, { stream: true });
      
      // Process complete lines
      const lines = buffer.split('\n');
      buffer = lines.pop(); // keep incomplete line
      
      for (const line of lines) {
        if (!line.startsWith('data: ')) continue;
        const data = line.slice(6).trim();
        if (data === '[DONE]') {
          finishReason = finishReason || 'stop';
          break;
        }
        
        let chunk;
        try { chunk = JSON.parse(data); } catch { continue; }
        
        const choice = chunk.choices?.[0];
        if (!choice) continue;
        
        const delta = choice.delta || {};
        const prevFinish = finishReason;
        finishReason = choice.finish_reason || finishReason;
        if (choice.finish_reason && choice.finish_reason !== prevFinish) {
          log('info', `finish_reason: ${choice.finish_reason}`);
        }
        
        // Reasoning content
        if (delta.reasoning_content) {
          assistantReasoning += delta.reasoning_content;
          onChunk({ type: 'reasoning', text: delta.reasoning_content, full: assistantReasoning });
        }
        
        // Text content — suppress if show_widget is already streaming
        // (some models like DeepSeek V4 Pro echo widget code as delta.content too)
        if (delta.content) {
          const widgetActive = Object.values(toolCallBuffers).some(b => b.name === 'show_widget');
          if (!widgetActive) {
            assistantText += delta.content;
            onChunk({ type: 'text', text: delta.content, full: assistantText });
          }
        }
        
        // Tool calls
        if (delta.tool_calls) {
          for (const tc of delta.tool_calls) {
            const idx = tc.index ?? 0;
            if (!toolCallBuffers[idx]) {
              toolCallBuffers[idx] = { id: '', name: '', args: '' };
            }
            const buf = toolCallBuffers[idx];
            if (tc.id) buf.id = tc.id;
            if (tc.function?.name && !buf.name) {
              buf.name = tc.function.name;
              log('info', `tool_call[${idx}]: ${tc.function.name}()`);
            } else if (tc.function?.name) {
              buf.name = tc.function.name;
            }
            if (tc.function?.arguments) {
              buf.args += tc.function.arguments;
              // Live widget streaming
              if (buf.name === 'show_widget') {
                const partialCode = extractWidgetCode(buf.args);
                if (partialCode && partialCode.length > 50) {
                  const title = extractWidgetTitle(buf.args);
                  if (title) $('widget-title').textContent = title.replace(/_/g,' ');
                  $('stream-badge').classList.add('visible');
                  const prevCodeLen = buf._lastCodeLen || 0;
                  buf._lastCodeLen = partialCode.length;
                  // Simulate progressive streaming for models (e.g. Qwen) that deliver
                  // tool call arguments in large single chunks instead of char-by-char
                  if (partialCode.length - prevCodeLen > 400) {
                    const STEP = 300;
                    const _gen = _renderGen;
                    for (let _ci = prevCodeLen + STEP; _ci < partialCode.length; _ci += STEP) {
                      ((_s) => setTimeout(() => {
                        if (_renderGen !== _gen) return;  // finalizeWidget fired — abort stale slice
                        scheduleWidgetUpdate(_s);
                      }, Math.floor((_ci - prevCodeLen) / STEP) * 100))(partialCode.slice(0, _ci));
                    }
                  }
                  scheduleWidgetUpdate(partialCode);
                }
              }
              onChunk({ type: 'tool_delta', index: idx, name: buf.name, args: buf.args });
            }
          }
        }
      }
      
      if (finishReason === 'stop' || finishReason === 'tool_calls') break;
    }
  } catch(e) {
    if (e.name !== 'AbortError') showError('Stream error: ' + e.message);
  }

  // Build result
  const toolCallsArr = Object.values(toolCallBuffers);
  // Normalize: some models emit finish_reason:'stop' even when tool calls exist.
  if (FEATURES.finishNorm && toolCallsArr.length > 0 && toolCallsArr.some(tc => tc.name)) {
    finishReason = 'tool_calls';
  }

  // GLM safety: if GLM returned no tool calls and no text, it likely timed out
  if (FEATURES.logSystem && isGlmModel() && toolCallsArr.length === 0 && !assistantText.trim()) {
    log('warn', 'GLM returned empty response — possible timeout or context overflow');
  }

  // Log empty-arg tool calls (model declared a tool but never sent args)
  for (const tc of toolCallsArr) {
    if (!tc.args.trim()) {
      log('warn', `${tc.name}() has empty args — model may not have read guidelines`);
    } else {
      log('ok', `${tc.name}() args: ${tc.args.length.toLocaleString()} chars | finish: ${finishReason}`);
    }
  }
  if (toolCallsArr.length === 0) {
    log('info', `text-only response: ${assistantText.length} chars | finish: ${finishReason}`);
  }

  onDone({
    assistantText,
    assistantReasoning,
    toolCalls: toolCallsArr,
    finishReason
  }, null);
}

// ==========================================
// TOOL EXECUTION
// ==========================================
function executeTool(name, argsStr) {
  let args;
  try { args = JSON.parse(argsStr); } catch { args = {}; }
  
  if (name === 'visualize_read_me') {
    const modules = args.modules || [];
    const guidelines = getModuleGuidelines(modules);
    return guidelines;
  }
  
  if (name === 'show_widget') {
    const title = args.title || 'widget';
    const code = args.widget_code || '';
    log('info', `show_widget widget_code: ${code.length} chars | title: ${title}`);
    if (!code) {
      log('warn', 'show_widget widget_code is empty — streaming partial will still render if available');
    }
    if (code) finalizeWidget(code, title);
    return `Widget rendered successfully. Title: ${title}`;
  }
  
  return `Tool ${name} executed.`;
}

// ==========================================
// WIDGET BUILDING (from original code)
// ==========================================
function buildWidgetPage(code) {
  const isSvg = code.trim().startsWith('<svg');
  const bodyStyle = 'margin:0;padding:0;background:transparent;';
  if (isSvg) {
    return `${SHELL_HTML.split('</head>')[0]}<style>${SVG_STYLES}</style></head><body style="${bodyStyle}">${code}</body></html>`;
  }
  return `${SHELL_HTML.split('</head>')[0]}<style>${SVG_STYLES}</style></head><body style="${bodyStyle}">${code}</body></html>`;
}

// ==========================================
// LOGGING (adapted for server)
// ==========================================
let _logCount = 0;
const _t0 = Date.now();
function log(level, msg) {
  _logCount++;
  const ms = (Date.now() - _t0).toLocaleString();
  const prefix = { info: '\x1b[36m', ok: '\x1b[32m', warn: '\x1b[33m', err: '\x1b[31m' }[level] || '';
  const suffix = '\x1b[0m';
  console.log(`${prefix}[${level.toUpperCase()}]${suffix} ${ms}ms ${msg}`);
}

// ==========================================
// SERVER-SIDE ORCHESTRATION
// Replaces the browser send() function
// Writes all state to Supabase DB instead of DOM
// ==========================================
async function runJob(jobId) {
  // Read job details from DB
  const { data: job, error: jobErr } = await supabase
    .from('jobs')
    .select('*')
    .eq('id', jobId)
    .single();
  if (jobErr || !job) {
    log('err', `Job ${jobId} not found: ${jobErr?.message}`);
    return;
  }

  // Build feature set from job config
  const jobFeatures = job.features || {};
  Object.keys(FEATURE_DEFAULTS).forEach(k => {
    if (jobFeatures[k] !== undefined) FEATURES[k] = jobFeatures[k];
    else FEATURES[k] = FEATURE_DEFAULTS[k];
  });

  // Set model
  let selectedModel = job.model || 'minimax-m2p7';
  // The model string might be just the short name or the full prefix
  if (!selectedModel.startsWith('accounts/')) {
    selectedModel = MODEL_PREFIX + selectedModel;
  }

  // Mark job as running
  await supabase.from('jobs').update({ status: 'running' }).eq('id', jobId);
  log('info', `─── job ${jobId} start | model: ${selectedModel} ───`);

  // Build messages array from DB
  const { data: dbMessages } = await supabase
    .from('messages')
    .select('*')
    .eq('job_id', jobId)
    .order('seq', { ascending: true });

  const systemPrompt = getEffectiveSystemPrompt();
  let messages = [{ role: 'system', content: systemPrompt }];

  if (dbMessages && dbMessages.length > 0) {
    for (const m of dbMessages) {
      if (m.role === 'user') {
        messages.push({ role: 'user', content: m.content });
      } else if (m.role === 'assistant' && m.content) {
        messages.push({ role: 'assistant', content: m.content });
      } else if (m.role === 'tool') {
        messages.push({ role: 'tool', tool_call_id: m.tool_call_id, content: m.content });
      } else if (m.role === 'assistant_tool_calls') {
        // Reconstruct assistant message with tool_calls
        const toolCalls = m.tool_calls_data || [];
        messages.push({
          role: 'assistant',
          content: m.content || null,
          tool_calls: toolCalls
        });
      }
    }
  }

  let isStreaming = true;
  let _renderGen = 0;

  // Helper: write a message to DB and push via Realtime
  async function writeMessage(role, content, extra = {}) {
    const { data: lastMsg } = await supabase
      .from('messages')
      .select('seq')
      .eq('job_id', jobId)
      .order('seq', { ascending: false })
      .limit(1)
      .single();
    const seq = (lastMsg?.seq || 0) + 1;
    await supabase.from('messages').insert({
      job_id: jobId,
      role,
      content,
      seq,
      ...extra
    });
  }

  // Helper: write widget update to DB
  async function writeWidget(code, title, isFinal) {
    // Upsert: one widget row per job, updated as streaming progresses
    const { data: existing } = await supabase
      .from('widgets')
      .select('id')
      .eq('job_id', jobId)
      .limit(1)
      .single();

    if (existing) {
      await supabase.from('widgets').update({
        code,
        title: title || 'widget',
        is_final: isFinal,
        updated_at: new Date().toISOString()
      }).eq('id', existing.id);
    } else {
      await supabase.from('widgets').insert({
        job_id: jobId,
        code,
        title: title || 'widget',
        is_final: isFinal
      });
    }
  }

  // Helper: write tool call to DB
  async function writeToolCall(name, args, status) {
    await supabase.from('tool_calls').insert({
      job_id: jobId,
      name,
      args: typeof args === 'string' ? args : JSON.stringify(args),
      status
    });
  }

  // Throttled widget writing for streaming
  let _lastWidgetWrite = 0;
  let _pendingWidgetCode = null;
  let _pendingWidgetTitle = null;
  let _widgetWriteInterval = null;

  function scheduleWidgetWrite(code, title) {
    _pendingWidgetCode = code;
    _pendingWidgetTitle = title;
    if (!_widgetWriteInterval) {
      _widgetWriteInterval = setInterval(async () => {
        if (_pendingWidgetCode) {
          await writeWidget(_pendingWidgetCode, _pendingWidgetTitle, false);
          _pendingWidgetCode = null;
        }
      }, 500); // Write widget to DB every 500ms during streaming
    }
  }

  function stopWidgetWriteInterval() {
    if (_widgetWriteInterval) {
      clearInterval(_widgetWriteInterval);
      _widgetWriteInterval = null;
    }
  }

  // The API key — from env or from job config
  const apiKey = FIREWORKS_API_KEY || job.api_key;
  if (!apiKey) {
    log('err', `No API key for job ${jobId}`);
    await supabase.from('jobs').update({ status: 'error', error: 'No API key configured' }).eq('id', jobId);
    return;
  }

  // Recursive multi-turn API call handler (adapted from send())
  async function doCall(forceTool) {
    const body = {
      model: selectedModel,
      messages: messages,
      tools: TOOLS,
      tool_choice: (FEATURES.forceNext && forceTool) ? { type: 'function', function: { name: forceTool } } : 'auto',
      stream: true,
      max_tokens: FEATURES.maxTokensHigh ? 131072 : 65536,
      temperature: FEATURES.tempOne ? 1 : 0.7,
      reasoning_effort: FEATURES.reasoningHigh ? 'high' : 'medium'
    };

    log('info', `→ ${selectedModel} | max_tokens:${body.max_tokens} | temp:${body.temperature} | tool_choice:${forceTool ? 'force:'+forceTool : 'auto'} | msgs:${messages.length}`);

    const resp = await fetch(API_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${apiKey}`,
        'Accept': 'text/event-stream'
      },
      body: JSON.stringify(body)
    });

    if (!resp.ok) {
      let errText = '';
      try { errText = await resp.text(); } catch(e2) {}
      let errMsg = `API error ${resp.status}`;
      try {
        const errJson = JSON.parse(errText);
        errMsg += ': ' + (errJson.error?.message || errJson.message || errText.slice(0, 100));
      } catch { errMsg += ': ' + errText.slice(0, 100); }
      log('err', `HTTP ${resp.status}: ${errMsg}`);
      await writeMessage('system', `Error: ${errMsg}`);
      return { assistantText: '', assistantReasoning: '', toolCalls: [], finishReason: 'error' };
    }

    // Read SSE stream
    const reader = resp.body.getReader();
    const decoder = new TextDecoder();
    let buffer = '';
    const toolCallBuffers = {};
    let currentToolIndex = -1;
    let assistantText = '';
    let assistantReasoning = '';
    let finishReason = null;

    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop();

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue;
          const data = line.slice(6).trim();
          if (data === '[DONE]') {
            finishReason = finishReason || 'stop';
            break;
          }

          let chunk;
          try { chunk = JSON.parse(data); } catch { continue; }
          const choice = chunk.choices?.[0];
          if (!choice) continue;

          const delta = choice.delta || {};
          finishReason = choice.finish_reason || finishReason;

          if (delta.reasoning_content) {
            assistantReasoning += delta.reasoning_content;
          }

          if (delta.content) {
            const widgetActive = Object.values(toolCallBuffers).some(b => b.name === 'show_widget');
            if (!widgetActive) {
              assistantText += delta.content;
            }
          }

          if (delta.tool_calls) {
            for (const tc of delta.tool_calls) {
              const idx = tc.index ?? 0;
              if (!toolCallBuffers[idx]) {
                toolCallBuffers[idx] = { id: '', name: '', args: '' };
              }
              const buf = toolCallBuffers[idx];
              if (tc.id) buf.id = tc.id;
              if (tc.function?.name && !buf.name) {
                buf.name = tc.function.name;
                log('info', `tool_call[${idx}]: ${tc.function.name}()`);
              } else if (tc.function?.name) {
                buf.name = tc.function.name;
              }
              if (tc.function?.arguments) {
                buf.args += tc.function.arguments;
                if (buf.name === 'show_widget') {
                  const partialCode = extractWidgetCode(buf.args);
                  if (partialCode && partialCode.length > 50) {
                    const title = extractWidgetTitle(buf.args);
                    scheduleWidgetWrite(partialCode, title);
                  }
                }
              }
            }
          }
        }
        if (finishReason === 'stop' || finishReason === 'tool_calls') break;
      }
    } catch(e) {
      log('err', `Stream error: ${e.message}`);
    }

    // Normalize finish reason
    const toolCallsArr = Object.values(toolCallBuffers);
    if (FEATURES.finishNorm && toolCallsArr.length > 0 && toolCallsArr.some(tc => tc.name)) {
      finishReason = 'tool_calls';
    }

    for (const tc of toolCallsArr) {
      if (!tc.args.trim()) {
        log('warn', `${tc.name}() has empty args`);
      } else {
        log('ok', `${tc.name}() args: ${tc.args.length.toLocaleString()} chars | finish: ${finishReason}`);
      }
    }
    if (toolCallsArr.length === 0) {
      log('info', `text-only response: ${assistantText.length} chars | finish: ${finishReason}`);
    }

    return { assistantText, assistantReasoning, toolCalls: toolCallsArr, finishReason };
  }

  // Main orchestration loop (adapted from send())
  try {
    // First API call
    const result1 = await doCall(undefined);

    if (result1.finishReason === 'error') {
      await supabase.from('jobs').update({ status: 'error' }).eq('id', jobId);
      stopWidgetWriteInterval();
      return;
    }

    // Write assistant text message
    if (result1.assistantText) {
      await writeMessage('assistant', result1.assistantText);
    }

    if (result1.toolCalls.length > 0) {
      // Build assistant message with tool_calls for messages array
      const assistantMsg = {
        role: 'assistant',
        content: result1.assistantText || null,
        tool_calls: result1.toolCalls.map(tc => ({
          id: tc.id || ('call_' + Math.random().toString(36).slice(2)),
          type: 'function',
          function: { name: tc.name, arguments: tc.args }
        }))
      };
      messages.push(assistantMsg);

      // Also store in DB as assistant_tool_calls
      await writeMessage('assistant_tool_calls', result1.assistantText || '', {
        tool_calls_data: assistantMsg.tool_calls
      });

      // Execute each tool
      for (let i = 0; i < result1.toolCalls.length; i++) {
        const tc = result1.toolCalls[i];
        const toolId = assistantMsg.tool_calls[i].id;

        log('info', `executing ${tc.name}()`);
        let toolResult;
        try {
          toolResult = executeTool(tc.name, tc.args);
          log('ok', `executed ${tc.name}() → ${typeof toolResult === 'string' ? toolResult.length.toLocaleString() + ' chars' : 'object'}`);
        } catch(e) {
          toolResult = 'Error: ' + e.message;
          log('err', `executeTool ${tc.name}() threw: ${e.message}`);
        }

        // Write tool result to DB
        await writeToolCall(tc.name, tc.args, 'done');

        messages.push({
          role: 'tool',
          tool_call_id: toolId,
          content: typeof toolResult === 'string' ? toolResult : JSON.stringify(toolResult)
        });
        await writeMessage('tool', typeof toolResult === 'string' ? toolResult : JSON.stringify(toolResult), { tool_call_id: toolId });
      }

      // If finish reason was tool_calls, continue with another API call
      if (result1.finishReason === 'tool_calls') {
        const lastToolName = result1.toolCalls[result1.toolCalls.length - 1]?.name || '';
        const forceNext = (FEATURES.forceNext && lastToolName === 'visualize_read_me') ? 'show_widget' : undefined;
        if (forceNext) log('info', `forcing tool_choice → ${forceNext}`);

        const result2 = await doCall(forceNext);

        if (result2.assistantText) {
          await writeMessage('assistant', result2.assistantText);
        }

        if (result2.toolCalls.length > 0) {
          const assistantMsg2 = {
            role: 'assistant',
            content: result2.assistantText || null,
            tool_calls: result2.toolCalls.map(tc => ({
              id: tc.id || ('call_' + Math.random().toString(36).slice(2)),
              type: 'function',
              function: { name: tc.name, arguments: tc.args }
            }))
          };
          messages.push(assistantMsg2);

          await writeMessage('assistant_tool_calls', result2.assistantText || '', {
            tool_calls_data: assistantMsg2.tool_calls
          });

          for (let i = 0; i < result2.toolCalls.length; i++) {
            const tc = result2.toolCalls[i];
            const toolId = assistantMsg2.tool_calls[i].id;

            let toolResult2;
            try {
              toolResult2 = executeTool(tc.name, tc.args);
              log('ok', `r2 executed ${tc.name}() → ${typeof toolResult2 === 'string' ? toolResult2.length.toLocaleString() + ' chars' : 'object'}`);
            } catch(e) {
              toolResult2 = 'Error: ' + e.message;
              log('err', `r2 executeTool ${tc.name}() threw: ${e.message}`);
            }

            await writeToolCall(tc.name, tc.args, 'done');
            messages.push({
              role: 'tool',
              tool_call_id: toolId,
              content: typeof toolResult2 === 'string' ? toolResult2 : JSON.stringify(toolResult2)
            });
            await writeMessage('tool', typeof toolResult2 === 'string' ? toolResult2 : JSON.stringify(toolResult2), { tool_call_id: toolId });
          }

          // One more call if needed (after show_widget)
          if (result2.finishReason === 'tool_calls') {
            const result3 = await doCall(undefined);
            if (result3.assistantText) {
              await writeMessage('assistant', result3.assistantText);
              messages.push({ role: 'assistant', content: result3.assistantText });
            }
          } else if (result2.assistantText) {
            messages.push({ role: 'assistant', content: result2.assistantText });
          }
        } else if (result2.assistantText) {
          messages.push({ role: 'assistant', content: result2.assistantText });
        }
      }
    } else {
      // No tool calls, just text
      if (result1.assistantText) {
        messages.push({ role: 'assistant', content: result1.assistantText });
      }
    }

    // Finalize widget if one was streamed
    stopWidgetWriteInterval();

    // Check if there's a finalized widget to write
    const { data: lastWidget } = await supabase
      .from('widgets')
      .select('code, title')
      .eq('job_id', jobId)
      .limit(1)
      .single();

    if (lastWidget) {
      await writeWidget(lastWidget.code, lastWidget.title, true);
    }

    // Mark job as completed
    await supabase.from('jobs').update({ status: 'completed' }).eq('id', jobId);
    log('ok', `─── job ${jobId} completed ───`);

  } catch(e) {
    log('err', `Job ${jobId} failed: ${e.message}\n${e.stack}`);
    stopWidgetWriteInterval();
    await supabase.from('jobs').update({ status: 'error', error: e.message }).eq('id', jobId);
  }
}

// ==========================================
// EXPRESS SERVER
// ==========================================
app.get('/health', (req, res) => {
  res.json({ status: 'ok', uptime: process.uptime() });
});

app.post('/run', async (req, res) => {
  const { job_id, secret } = req.body;
  if (secret !== WORKER_SECRET) {
    return res.status(403).json({ error: 'Invalid worker secret' });
  }
  if (!job_id) {
    return res.status(400).json({ error: 'job_id required' });
  }

  // Start the job asynchronously — don't wait for completion
  res.json({ status: 'started', job_id });

  // Run in background
  runJob(job_id).catch(e => {
    console.error(`Fatal error in job ${job_id}:`, e);
  });
});

app.listen(PORT, () => {
  console.log(`Imagine Worker listening on port ${PORT}`);
});
